css:
@page { size: A4; margin: 0; }

body {
  margin: 0;
  padding: 16mm 18mm;
  background: #0b0f17;
  color: #e6eaf2;
  font-family: 'Helvetica', 'Arial', sans-serif;
  -webkit-print-color-adjust: exact;
  print-color-adjust: exact;
}
.num { font-variant-numeric: tabular-nums; }
.mono { font-family: 'Courier New', monospace; }
.doc-header { display: block; margin: 0; }

.dk-top { display: flex; align-items: center; justify-content: space-between; }
.dk-brand { display: flex; align-items: center; gap: 3.5mm; }
.dk-mark { height: 11mm; width: 11mm; display: block; }
.dk-brandname { font-size: 12pt; font-weight: 700; color: #fff; letter-spacing: -0.01em; }
.dk-doc { text-align: right; }
.dk-eyebrow { display: block; font-size: 8pt; letter-spacing: 0.26em; text-transform: uppercase; color: #22d3ee; font-weight: 700; }
.dk-docno { display: block; font-size: 16pt; font-weight: 800; color: #fff; margin-top: 1mm; }
.dk-accent { height: 1.2mm; border-radius: 1mm; margin: 5mm 0 8mm; background: linear-gradient(90deg, #818cf8 0%, #22d3ee 50%, #21c39a 100%); }

/* Cards */
.dk-cards { display: flex; gap: 5mm; margin-bottom: 8mm; }
.dk-card { flex: 1 1 0; background: #141a26; border: 1px solid #232b3b; border-radius: 3mm; padding: 5mm; }
.dk-k { font-size: 7pt; letter-spacing: 0.16em; text-transform: uppercase; color: #6b7488; font-weight: 700; }
.dk-strong { font-weight: 700; color: #fff; font-size: 11pt; margin-top: 1.5mm; }
.dk-dim { color: #aeb6c6; font-size: 9.5pt; line-height: 1.5; }
.dk-row { display: flex; justify-content: space-between; padding: 1.4mm 0; font-size: 9.5pt; }
.dk-row .dk-k { align-self: center; }
.dk-row span:last-child { color: #fff; font-weight: 600; }

/* Items */
.dk-items { width: 100%; border-collapse: collapse; margin-bottom: 8mm; }
.dk-items thead th { font-size: 7pt; letter-spacing: 0.12em; text-transform: uppercase; color: #6b7488; font-weight: 700; text-align: left; padding: 0 3mm 3mm; border-bottom: 1px solid #2a3346; }
.dk-items tbody td { padding: 3.2mm 3mm; border-bottom: 1px solid #1a2230; vertical-align: top; }
.dk-c-pos { width: 10mm; color: #5a6urple; color: #5b6party; }
.dk-c-pos { width: 10mm; color: #586079; }
.dk-c-hs { width: 24mm; color: #aeb6c6; }
.dk-c-org { width: 22mm; color: #aeb6c6; }
.dk-c-qty { width: 22mm; text-align: right; color: #cfd5e2; }
.dk-c-total { width: 30mm; text-align: right; font-weight: 700; color: #fff; }
.dk-c-desc strong { color: #fff; font-weight: 700; }
.dk-sku { display: block; color: #586079; font-size: 8pt; margin-top: 0.6mm; }
thead th.dk-c-qty, thead th.dk-c-total { text-align: right; }

/* Footer split */
.dk-foot { display: flex; gap: 8mm; align-items: stretch; }
.dk-note { flex: 1 1 0; }
.dk-note p { color: #aeb6c6; font-size: 8.5pt; line-height: 1.5; margin-top: 1.6mm; max-width: 100mm; }
.dk-totals { flex: 0 0 70mm; background: #141a26; border: 1px solid #232b3b; border-radius: 3mm; padding: 5mm; }
.dk-trow { display: flex; justify-content: space-between; gap: 4mm; padding: 1.5mm 0; font-size: 10pt; color: #aeb6c6; }
.dk-trow--grand { margin-top: 2mm; padding-top: 3mm; border-top: 1px solid #2a3346; font-size: 14pt; font-weight: 800; color: #fff; }
.dk-trow--grand .num { color: #22d3ee; }

.dk-pagefoot { display: flex; justify-content: space-between; margin-top: 12mm; padding-top: 4mm; border-top: 1px solid #1a2230; font-size: 7pt; color: #586079; }
